import{_ as p,o as a,c as e,j as r,a as t,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const h=JSON.parse('{"title":"战争终幕曲","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/通用及综合类/战争终幕曲.md","filePath":"4.资源分区/6.技艺及称号/通用及综合类/战争终幕曲.md"}'),n={name:"4.资源分区/6.技艺及称号/通用及综合类/战争终幕曲.md"};function o(d,b,_,l,i,c){return a(),e("div",null,[...b[0]||(b[0]=[r("h1",{id:"战争终幕曲",tabindex:"-1"},[t("战争终幕曲 "),r("a",{class:"header-anchor",href:"#战争终幕曲","aria-label":'Permalink to "战争终幕曲"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：灵魂蓝调018")])])],-1),s('<h1 id="战争终幕曲-1" tabindex="-1">战争终幕曲 <a class="header-anchor" href="#战争终幕曲-1" aria-label="Permalink to &quot;战争终幕曲&quot;">​</a></h1><p>战争终幕曲<br> 描述：战争从未停止。依然活动的行尸走肉，推动死亡的士兵们，这是永无止歇的战争，连绵不绝的炮火宛如摇篮曲一样，这并非是断续的清谣，而是连续、沉重，仅属于生命消逝前的歌唱。<br> 即使如此。正是如此。<br> 即使是这样的世界，人们还是有着想要守护的事物。想要的话那就行动吧！战斗吧！前进吧！正因为是为了追求得以守护之物而前进，挡在战争的恶魔与真正的绝望之前的，是名为坚强的守护之盾。<br> 注：该资源主干不会提供自由属性。</p><p>价格：D+500<br> 描述：血腥和杀戮的风掀起的尘埃苍黄，就这样吹散了归来者的过往，仅仅残留的稀薄记忆，与截然不同的世界。<br> 没关系、没有问题，这根本没什么。<br> 疼痛、艰辛、苦楚、悲伤，活着的时候无法守护的东西，那么现在就来好好守护。</p><p>归还者：由于归还者的本质，你获得黑暗生物特性。特殊的是，因此获得的黑暗生物是可以与光明生物本质共存的，但计算任何涉及到光明/黑暗生物的判断中，你的光明/黑暗生物类型取劣计算，包括前提，效果，特攻等部分。</p><p>埋葬青涩：当你直面敌人时，你便有无可比拟的勇气。<br> 你在进行冲锋时无视冲锋在基础防御上带来的减值，同时若在攻击时具有恐惧异常不良点数，则先将其移除1点，每轮最多只能因此移除1点不良点数，移除上限24，上限可以通过长休息恢复。</p><p>生命之重：你开启了一个特殊的专属刻度负担值，它的初始数值为零，而上限等于你的全属性上的传奇属性之和。<br> 骑士下属的每一件专属物品都会提升负担值，每装备1件会按照等阶（基础1精良2进阶3传说4神圣5）提升负担值，超过负担值上限时所有专属装备将失去效果。</p><p>专属物品<br> 躯壳下沉，灵魂上升，在日常的锻炼中饱含秩序力量的尸体不会浪费，而是在沉淀之后形成被称之为“基石”的产物。若能理清其中残留的思念，就能其中获取力量，这是唯有归还者才能承担的生命之重。</p><p>士兵的勇力<br> 价格：500<br> 等级：基础<br> 分类：手套<br> 描述：无名的士兵，无名的勇士，挺身而出的人被誉为勇者，同样是在战争中微不足道的伤亡数字，作为基石锻造出的装备而言，可以赋予穿戴者微弱的勇力。<br> 基石武装：若非具有归还者特性的单位试图主动装备这件物品，则其立刻视为处于重量超载状态。同时，这件物品不会为具有归还者以外的单位提供任何效果。<br> 勇力增幅：你的力量相关检定获得1DP器械加值，你在意志豁免上获得2DP器械加值。</p><p>传令兵的俊敏<br> 价格：500<br> 等级：基础<br> 分类：鞋子<br> 描述：无名的传令兵，奔跑在战争之中传达命令，他们往往死的很快，再由下一个传令兵接过染血的信封，作为基石锻造出的装备而言，可以赋予穿戴者微弱俊敏。<br> 基石武装：若非具有归还者特性的单位试图主动装备这件物品，则其立刻视为处于重量超载状态。同时，这件物品不会为具有归还者以外的单位提供任何效果。<br> 敏捷增幅：你的基础防御增加1点，你的基础移动速度提升5米。</p><p>盾卫的坚韧<br> 价格：500<br> 等级：基础<br> 分类：披风<br> 描述：无名的盾卫，位于最前方抵挡最猛烈攻击的他们伤亡率也是最高的。作为基石锻造出的装备而言，可以赋予穿戴者微弱的防御能力。<br> 基石武装：若非具有归还者特性的单位试图主动装备这件物品，则其立刻视为处于重量超载状态。同时，这件物品不会为具有归还者以外的单位提供任何效果。<br> 防御增强：你增加1点天生防御，在强韧检定上获得2DP的器械加值。</p><p>刺客的呼吸<br> 价格：D+500<br> 等级：精良<br> 分类：披风<br> 描述：无名的刺客，能够与周围环境融为一体，他们的攻击有效而致命，然而在名为战争的恶魔之前，这只是微不足道的抵抗。作为基石锻造出的装备而言，可以赋予穿戴者些许的隐匿能力。<br> 基石武装：若非具有归还者特性的单位试图主动装备这件物品，则其立刻视为处于重量超载状态。同时，这件物品不会为具有归还者以外的单位提供任何效果。<br> 黑暗呼吸：以一个标准动作和1点意志力，你进入隐身状态，在对抗侦查的检定中获得2DP器械加值。这是一个C级的魔幻本质反侦测能力，持续一场景。</p><p>荒原的行者<br> 价格：D+500<br> 等级：精良<br> 分类：鞋子<br> 描述：因投身于卫国战役而牺牲的无名之人，其很擅长在任何地形下移动，悠然自在的于荒野之上独自生活……曾经如此。作为基石锻造出的装备而言，可以赋予穿戴者些许的地形移动能力。<br> 基石武装：若非具有归还者特性的单位试图主动装备这件物品，则其立刻视为处于重量超载状态。同时，这件物品不会为具有归还者以外的单位提供任何效果。<br> 荒野行动：你免疫C级困难地形，并且你的基础移动速度提升自身内在最高支线等级*10米。</p><p>壁垒的盾卫<br> 价格：D+500<br> 等级：精良<br> 分类：腰带<br> 描述：结阵而列的他们位于第一线抵抗最致命的冲击，以手中的盾宣誓决不退让，而结果显现如此。作为基石锻造出的装备而言，可以赋予穿戴者些许的韧性与防御能力提升。<br> 基石武装：若非具有归还者特性的单位试图主动装备这件物品，则其立刻视为处于重量超载状态。同时，这件物品不会为具有归还者以外的单位提供任何效果。<br> 韧性提升：你在天生防御上获得自身内在最高支线等级*1点的加值，此外获得1点可叠加的全伤害吸收效果，基于天生防御。</p><p>生命增强：你的生命值上限提升1点。</p><p>不破之盾<br> 价格：C+1000<br> 等级：进阶<br> 分类：手腕<br> 描述：被誉为“不破之盾”骑士自傲于防御能力，他相信着自己可以保护同伴，也相信着同伴的力量，直到大量的敌军淹没了他最后的踪迹。作为基石锻造出的装备而言，可以赋予穿戴者较高的伤害减免能力，以及防御性能的提升。<br> 基石武装：若非具有归还者特性的单位试图主动装备这件物品，则其立刻视为处于重量超载状态。同时，这件物品不会为具有归还者以外的单位提供任何效果。</p><p>危机守护：你的盔甲防御提升5点，若盔甲防御因其他原因改变了类型，则该效果提供的防御也会相应转变。<br> 此外，你可以使用一个迅捷动作消耗1点意志力，激发不破之盾的防护能力，你立即获得2点全伤害吸收、以及基于盔甲防御的2点反伤效果，伤害类型为物理-钝击，持续一个场景。</p><p>魔动武装<br> 价格：C+1000<br> 等级：进阶<br> 分类：手腕<br> 描述：有一位魔导师开创了新的体系，能够将战士与法师的的能量激发，大幅度提升其本身的力量、速度、防御，这位本应名留青史之人埋葬在了最后的战役之下。<br> 作为基石锻造出的装备而言，可以赋予穿戴者转换能量均衡提升各方面素质的能力。<br> 基石武装：若非具有归还者特性的单位试图主动装备这件物品，则其立刻视为处于重量超载状态。同时，这件物品不会为具有归还者以外的单位提供任何效果。</p><p>澎湃动能：你可以使用任意一种生理类通用能量或是魔力能量驱动这个效果。当你的对应能量池不为空时，你在防御上获得3点偏斜加值，你可以使用自由动作驱动效果，这需要消费2点能量，使本轮内你的力量检定、反射豁免、偏斜防御上再获得5DP加值。<br> 魔能反冲：你可以在自然坠落时使用动能反冲来避免坠落伤害，这视为免疫自然坠落伤害的效果。</p><p>裁决突击<br> 价格：C+1000<br> 等级：进阶<br> 分类：护符<br> 描述：银色的教团主张和平，他们曾试图组织信徒来为难民突围，怀抱信仰直至最后一刻。作为基石锻造出的装备而言，可以赋予穿戴者较高的反应能力，以及行动速度上的强化。<br> 基石武装：若非具有归还者特性的单位试图主动装备这件物品，则其立刻视为处于重量超载状态。同时，这件物品不会为具有归还者以外的单位提供任何效果。</p><p>速度提升：你的近战攻击增加5点高速效果，你的先攻提升自身内在最高支线*4点。<br> 突出重围：你免疫多次攻击减值，同时在反射检定上获得4DP的器械加值。</p><p>生命诛绝<br> 价格：C+1000<br> 等级：进阶<br> 分类：面具<br> 描述：西方的战士从不畏惧战斗，他们越是受伤，就能发挥出越加狂暴的力量，于是死亡如严冬般降临。作为基石锻造出的装备而言，可以赋予穿戴者抽取自身生命力，较高程度的攻击提升。<br> 基石武装：若非具有归还者特性的单位试图主动装备这件物品，则其立刻视为处于重量超载状态。同时，这件物品不会为具有归还者以外的单位提供任何效果。</p><p>狂战士：自由动作，对自己造成2点不可避免的韧性伤害，你使本场景内的攻击检定获得2个附加成功。<br> 若你的生命值没有完好，则你可以迅捷动作进行一次额外的移动或是格挡，这两种效果每轮合计能使用一次。</p><p>黑暗献祭<br> 价格：B+2000<br> 等级：传说<br> 分类：斗篷<br> 描述：向黑暗献祭的传奇骑士是如此强大，强大到直逼五阶的程度，他可以源源不断的恢复自身的肉体损伤，因此才会流干了最后一滴血液。<br> 作为基石锻造出的装备而言，可以赋予穿戴者生理属性的强力增幅，以及恢复生命的力量。<br> 基石武装：若非具有归还者特性的单位试图主动装备这件物品，则其立刻视为处于重量超载状态。同时，这件物品不会为具有归还者以外的单位提供任何效果。</p><p>黑暗守护：你的生理系属性检定获得4DP亵渎加值，同时获得等同于自身传奇耐力的【快速医疗】与【吸血】，医疗点数为快速医疗*12点。<br> 越战越勇：你获得自适应短休与自适应长休息的效果，以及针对疲乏点数的1点恢复能力，医疗点数24。</p><p>深红流火<br> 价格：B+2000<br> 等级：传说<br> 分类：戒指<br> 描述：被称为深红流火的大魔导师最擅长毁灭性的攻击，所招至的火焰可以形成席卷军队的火流星，正如她在最后的战场上一样，徇烂夺目而转瞬即逝。<br> 作为基石锻造出的装备而言，可以大幅度提升火焰系能力的效果，并使攻击变成范围的火焰伤害。<br> 基石武装：若非具有归还者特性的单位试图主动装备这件物品，则其立刻视为处于重量超载状态。同时，这件物品不会为具有归还者以外的单位提供任何效果。</p><p>炎阳：你的攻击中如果具有火焰系能力的效果，则使这次攻击获得【湮灭】特性，同时使伤害类型转变为火焰伤害。<br> 流星：你在攻击时可以选择使本次攻击范围变更为范围攻击，攻击范围是半径等同于自身传奇智力*10米的圆形，射程则等同于攻击范围，同时攻击范围内的所有敌人，敌人使用强韧检定进行豁免伤害。</p><p>天国武装<br> 价格：A+4000<br> 等级：神圣<br> 分类：腰带<br> 描述：传说中的神圣骑士，具有压倒性力量的骑士之王，曾经斩杀过无数的魔鬼、恶魔、堕落天民、星兽、阴影和远古巨人，即使如此，岁月依旧无情的夺去了他全盛时期的力量。<br> 作为基石锻造出的装备而言，可以赋予穿戴者巨额的增强，以及针对黑暗生物的灭杀能力……即使这只是残留的力量。<br> 基石武装：若非具有归还者特性的单位试图主动装备这件物品，则其立刻视为处于重量超载状态。同时，这件物品不会为具有归还者以外的单位提供任何效果。</p><p>天使之佑：你的全检定获得内在最高支线等级*2DP神圣加值，这个加值同样应用于防御上；你造成的所有伤害自动转为正能量伤害类型。<br> 仅针对亵渎/黑暗能量伤害，你获得12点能量抗力。</p><p>璀璨明星：每轮一次，你对黑暗生物、不死生物造成的伤害增加一半；以及在针对其的攻击检定上获得自身内在最高支线等级*1DP和附加成功。</p><p>光翼：以一个自由动作，你可以激发出一对由纯粹光能构造的光翼，持续一个场景。这对光翼没有任何用处，只是纯粹的装饰物，它也无法使你飞上天空，但是这对光翼既璀璨又徇丽，看着很漂亮，会使你看着很高贵。这对拉风的光翼，正是骑士之王同样也是神圣骑士名号的由来。</p><p>深蓝咏叹<br> 价格：A+4000<br> 等级：神圣<br> 分类：戒指<br> 描述：王国的圣女，亦是亡国的王女最后的咏叹，据说她能够沟通星海，赋予麾下骑士们星辰之力，那是悠久宁静，本应是并非用于战争的力量，但这却只是历史微不足道的一页。<br> 作为基石锻造出的装备而言，可以赋予穿戴者无上限的恢复效果，以及些许的增益。<br> 基石武装：若非具有归还者特性的单位试图主动装备这件物品，则其立刻视为处于重量超载状态。同时，这件物品不会为具有归还者以外的单位提供任何效果。</p><p>深星祝福：你指定自身一个能力带来的快速医疗池，该能力的医疗点在每场景结束后恢复至上限。<br> 深蓝冥想：你指定自身一个通用能量池，该能量池每小时可以进行一次关键属性检定，恢复成功数点能量，这不会改变每日恢复上限。<br> 血脉提升：你在强韧豁免获得6DP器械加值，同时增加这个数值一半的耐力属性，这些属性如果溢出，会以1：2的形式增加到强韧豁免的器械加值上。</p><p>专属技能<br> 白昼黎明<br> 价格：C+1250<br> 动作：移动动作<br> 消耗：2点（意志力）<br> 类型：防御技<br> 描述：“熊熊圣焰，燃我残躯，愿黎明终将到来。”<br> 神圣的力量自骑士的身躯喷涌而出，化为炽烈的火焰熊熊燃烧，纯白的灼热光芒会伤害所有攻击骑士的敌人。<br> 效果：你使用一个移动动作进入【白昼】状态，【白昼】状态之下，你受到伤害时返还自身传奇决心*1点神圣/正能量伤害，基于天生防御，这个效果将持续一场景。<br> 在【白昼】持续时间内，你的攻击会附带等同于伤害出目的目眩+耳聋异常点数，标准豁免。</p><hr><p>Copyright ? 2024 TMDtrpg制作组. All Rights Reserved.</p>',35)])])}const P=p(n,[["render",o]]);export{h as __pageData,P as default};
